def gen(rng, size):
    bases = 'ACGT'
    def rand_gene():
        return ''.join(rng.choice(bases) for _ in range(8))
    start = rand_gene()
    bank = [rand_gene() for _ in range(min(size, 10))]
    end = bank[rng.randrange(len(bank))]
    return [start, end, bank]

