class Solution:
    def minMutation(self, startGene: str, endGene: str, bank) -> int:
        bank_set = set(bank)
        if endGene not in bank_set:
            return -1
        from collections import deque
        q = deque([(startGene, 0)])
        visited = {startGene}
        while q:
            gene, steps = q.popleft()
            if gene == endGene:
                return steps
            for i in range(8):
                for c in 'ACGT':
                    if c != gene[i]:
                        nb = gene[:i] + c + gene[i+1:]
                        if nb in bank_set and nb not in visited:
                            visited.add(nb)
                            q.append((nb, steps + 1))
        return -1

